chart.options:
chart: {
  type: 'donut',
},
labels: ['Mobile', 'Desktop', 'Tablet', 'Smart TV', 'Wearable'],
title: {
  text: 'Sessions by Device',
  align: 'center'
},
plotOptions: {
  pie: {
    startAngle: -90,
    endAngle: 90,
    offsetY: 10,
    dataLabels: {
      external: {
        show: true,
        formatter: function (name, opts) {
          return [name, Math.round(opts.percent) + '%']
        }
      }
    }
  }
},
dataLabels: {
  enabled: false
},
legend: {
  show: false
},
grid: {
  padding: {
    bottom: -80
  }
},
responsive: [{
  breakpoint: 480,
  options: {
    chart: {
      width: 300
    }
  }
}]
